// InmoBroker - Validación y Estructuración de Datos v1.0
const input = $input.first().json;
const body = input.body || input;

// Extraer datos del formulario
const datos = {
  // Datos del inquilino (titular)
  inquilino: {
    cedula: body.inquilino_cedula || body.cedula || '',
    nombre: body.inquilino_nombre || body.nombre || '',
    email: body.inquilino_email || body.email || '',
    telefono: body.inquilino_telefono || body.telefono || '',
  },

  // Datos del inmueble
  inmueble: {
    direccion: body.direccion || '',
    ciudad: body.ciudad || '',
    canon_mensual: parseFloat(body.canon_mensual) || 0,
  },

  // Deudor solidario 1 (obligatorio)
  deudor1: {
    cedula: body.deudor1_cedula || '',
    nombre: body.deudor1_nombre || '',
    telefono: body.deudor1_telefono || '',
  },

  // Deudor solidario 2 (solo si canon > 5M)
  deudor2: {
    cedula: body.deudor2_cedula || null,
    nombre: body.deudor2_nombre || null,
    telefono: body.deudor2_telefono || null,
  },

  // Archivos recibidos (base64 o URLs)
  documentos: {
    cedula_inquilino: body.doc_cedula_inquilino || null,
    extractos_bancarios: body.doc_extractos || [],
    certificado_laboral: body.doc_certificado_laboral || null,
    declaracion_renta: body.doc_declaracion_renta || null,
    cedula_deudor1: body.doc_cedula_deudor1 || null,
    extractos_deudor1: body.doc_extractos_deudor1 || [],
    cedula_deudor2: body.doc_cedula_deudor2 || null,
    extractos_deudor2: body.doc_extractos_deudor2 || [],
  },

  // Metadatos
  solicitud_id: body.inquilino_cedula || body.cedula || `SOL-${Date.now()}`,
  fecha_recepcion: new Date().toISOString(),
  requiere_deudor2: (parseFloat(body.canon_mensual) || 0) > 5000000,
};

// Validaciones
const errores = [];

if (!datos.inquilino.cedula) errores.push('Falta cédula del inquilino');
if (!datos.inquilino.nombre) errores.push('Falta nombre del inquilino');
if (!datos.inquilino.email) errores.push('Falta email del inquilino');
if (!datos.inmueble.canon_mensual) errores.push('Falta canon mensual');
if (!datos.deudor1.cedula) errores.push('Falta cédula del deudor solidario 1');

// Validar deudor 2 si aplica
if (datos.requiere_deudor2 && !datos.deudor2.cedula) {
  errores.push('Canon > $5M requiere segundo deudor solidario');
}

// Validar documentos mínimos
if (!datos.documentos.cedula_inquilino) errores.push('Falta foto de cédula del inquilino');
if (!datos.documentos.extractos_bancarios || datos.documentos.extractos_bancarios.length < 3) {
  errores.push('Se requieren 3 extractos bancarios');
}
if (!datos.documentos.certificado_laboral && !datos.documentos.declaracion_renta) {
  errores.push('Se requiere certificado laboral o declaración de renta');
}

return {
  json: {
    valido: errores.length === 0,
    errores: errores,
    datos: datos,
    solicitud_id: datos.solicitud_id
  }
};

// Preparar documentos para subir a Drive
const datos = $('Validar Datos Recibidos').first().json.datos;
const carpetaId = $('Crear Carpeta en Drive').first().json.id;
const solicitudId = datos.solicitud_id;

const documentosParaSubir = [];

// Función para agregar documento si existe
const agregarDoc = (doc, nombre, tipo) => {
  if (doc) {
    documentosParaSubir.push({
      contenido: doc,
      nombre: `${solicitudId}_${nombre}`,
      tipo: tipo,
      carpeta_id: carpetaId
    });
  }
};

// Documentos del inquilino
agregarDoc(datos.documentos.cedula_inquilino, 'cedula_inquilino', 'cedula');
agregarDoc(datos.documentos.certificado_laboral, 'certificado_laboral', 'certificado');
agregarDoc(datos.documentos.declaracion_renta, 'declaracion_renta', 'declaracion');

// Extractos bancarios del inquilino
if (datos.documentos.extractos_bancarios && Array.isArray(datos.documentos.extractos_bancarios)) {
  datos.documentos.extractos_bancarios.forEach((extracto, i) => {
    agregarDoc(extracto, `extracto_inquilino_${i+1}`, 'extracto');
  });
}

// Documentos deudor 1
agregarDoc(datos.documentos.cedula_deudor1, 'cedula_deudor1', 'cedula');
if (datos.documentos.extractos_deudor1 && Array.isArray(datos.documentos.extractos_deudor1)) {
  datos.documentos.extractos_deudor1.forEach((extracto, i) => {
    agregarDoc(extracto, `extracto_deudor1_${i+1}`, 'extracto');
  });
}

// Documentos deudor 2 (si aplica)
if (datos.requiere_deudor2) {
  agregarDoc(datos.documentos.cedula_deudor2, 'cedula_deudor2', 'cedula');
  if (datos.documentos.extractos_deudor2 && Array.isArray(datos.documentos.extractos_deudor2)) {
    datos.documentos.extractos_deudor2.forEach((extracto, i) => {
      agregarDoc(extracto, `extracto_deudor2_${i+1}`, 'extracto');
    });
  }
}

return documentosParaSubir.map(doc => ({ json: doc }));

// Convertir base64/URL a binario para subir a Drive
const doc = $input.first().json;

// Si es base64, convertir a binario
if (doc.contenido && doc.contenido.startsWith('data:')) {
  // Extraer el base64 puro (sin el prefijo data:...;base64,)
  const base64Data = doc.contenido.split(',')[1];
  const mimeMatch = doc.contenido.match(/data:([^;]+);/);
  const mimeType = mimeMatch ? mimeMatch[1] : 'application/pdf';

  return {
    json: doc,
    binary: {
      data: {
        data: base64Data,
        mimeType: mimeType,
        fileName: `${doc.nombre}.${mimeType.split('/')[1] || 'pdf'}`
      }
    }
  };
} else if (doc.contenido) {
  // Si es texto plano base64
  return {
    json: doc,
    binary: {
      data: {
        data: doc.contenido,
        mimeType: 'application/pdf',
        fileName: `${doc.nombre}.pdf`
      }
    }
  };
}

return { json: doc };
